// // This module implements a 16-bit DRAM cell where data is written to the cell on the falling edge of the clock when the RW signal is low.
module dram_cell (  
    input wire [15:0] data_in,  
    input wire rw,  
    input wire clk,  
    output reg [15:0] data_out  
);  
    reg [15:0] memory;  

    always @(posedge clk) begin  
        if (rw)  
            memory <= data_in;  
        else  
            data_out <= memory;  
    end  
endmodule
